import React, {type PropsWithChildren, useEffect, useState} from "react";
import {Button, Flex} from "../../../../_compat";
import {useTable} from "../../context";
import KitsInputText from "../../../../form/inputs/InputText";
import {Icon} from "../../../../primitives/Icon";
import {useComponentDefaults, useResolvedStyle} from "../../../../hooks";

function getQueryParams() {
  const url = window.location.href;
  var urlObj = new URL(url);
  var searchParams = new URLSearchParams(urlObj.search);
  var params = {};
  // @ts-ignore
  for (let key of searchParams.keys()) {
    // @ts-ignore
    params[key] = searchParams.get(key);
  }
  return params;
}

const TableHeader = ({ children }:PropsWithChildren) => {
  const {
    onGlobalFilterChange,
    globalFilterValue,
    text,
    globalSearch,
    stateful,
    columns,
    refValues,
    dataList,
    onClearFilter,
    onClearCache,
    resizableColumns,
    fileName,
    buttons,
    serverSideRequest,
    tableRef,
  } = useTable();

  const [localSearch, setLocalSearch] = useState(globalFilterValue);

  // Sync external → local (e.g. when clear filter button is pressed)
  useEffect(() => {
    setLocalSearch(globalFilterValue);
  }, [globalFilterValue]);

  // ── Theme: read tableHeader + searchInput slots ──
  const {elementStyles} = useComponentDefaults('Table', {} as any);
  const tableHeaderStyle = useResolvedStyle(elementStyles.tableHeader || {});
  const searchInputStyle = useResolvedStyle(elementStyles.searchInput || {});

  const isDev = "dev" in getQueryParams();

  const exportColumns = columns.map((col) => ({
    title: col.label,
    dataKey: col.name,
  }));

  const exportCSV = (selectionOnly: boolean) => {
    tableRef.current?.exportCSV({ selectionOnly });
  };

  const exportPdf = () => {
    import("jspdf").then((jsPDF) => {
      import("jspdf-autotable").then((value) => {
        const doc = new jsPDF.default("landscape", "px");

        value.default(doc, {
          columns: exportColumns,
          body: dataList,
        });
        doc.save(fileName + ".pdf");
      });
    });
  };

  const exportExcel = () => {
    // @ts-ignore
    import("xlsx").then((xlsx) => {
      const worksheet = xlsx.utils.json_to_sheet(dataList);
      const workbook = { Sheets: { data: worksheet }, SheetNames: ["data"] };
      const excelBuffer = xlsx.write(workbook, {
        bookType: "xlsx",
        type: "array",
      });

      saveAsExcelFile(excelBuffer);
    });
  };

  const saveAsExcelFile = (buffer: any) => {
    import("file-saver").then((module) => {
      if (module && module.default) {
        let EXCEL_TYPE =
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8";
        let EXCEL_EXTENSION = ".xlsx";
        const data = new Blob([buffer], {
          type: EXCEL_TYPE,
        });

        module.default.saveAs(
          data,
          fileName + "_export_" + new Date().getTime() + EXCEL_EXTENSION,
        );
      }
    });
  };

  return (
    <Flex
      justifyContent={[
        "flex-start",
        "flex-start",
        "flex-start",
        "space-between",
        "space-between",
      ]}
      flexDirection={["column", "column", "column", "row", "row"]}
      gap={2}
      style={tableHeaderStyle}
    >
      <Flex
        flex={1}
        gap={2}
        flexDirection={["column", "column", "column", "row", "row"]}
      >
        {globalSearch && (
          <KitsInputText
            value={localSearch ?? ''}
            onChange={(e: any) => setLocalSearch(e.target?.value ?? e ?? '')}
            onKeyDown={(e: any) => {
              if (e.key === 'Enter') {
                onGlobalFilterChange(localSearch);
              }
            }}
            onBlur={() => onGlobalFilterChange(localSearch)}
            placeholder={text.globalFilterPlaceholder}
            inputSize="sm"
            leftAddon={<Icon name="search" size="xs" color="text-secondary" />}
          />
        )}

        {children}
      </Flex>
      <Flex
        flex={1}
        gap={10}
        h={"2.5rem"}
        justifyContent={"flex-end"}
        flexDirection={"row"}
      >
        {buttons?.exportAsPdf && (
          <Button
            type="button"
            icon="pi pi-file-pdf"
            tooltipOptions={{
              position: "left",
            }}
            raised={false}
            style={{
              h: "2.5rem",
              border: "none",
            }}
            tooltip={text.exportAsPdf}
            size={"sm"}
            onClick={() => {
              exportPdf();
            }}
          />
        )}
        {buttons?.exportAsCSV && (
          <Button
            type="button"
            icon="pi pi-download"
            tooltipOptions={{
              position: "left",
            }}
            style={{
              h: "2.5rem",
              border: "none",
            }}
            raised={false}
            tooltip={text.exportAsCSV}
            size={"sm"}
            onClick={() => {
              exportExcel();
            }}
          />
        )}

        {buttons?.moreButtons
          ? buttons?.moreButtons(refValues).map((t, index) => (
              <Flex h={"full"} key={index}>
                {t}
              </Flex>
            ))
          : null}
        {Object.entries(serverSideRequest.filters).length > 0 && (
          <Button
            type="button"
            icon="pi pi-filter-slash"
            tooltipOptions={{
              position: "left",
            }}
            style={{
              h: "2.5rem",
              border: "none",
            }}
            severity="danger"
            tooltip={text.clearFilter}
            size={"sm"}
            onClick={onClearFilter}
          />
        )}

        {!!stateful && isDev && (
          <Button
            type="button"
            icon="pi pi-server"
            tooltipOptions={{
              position: "left",
            }}
            style={{
              h: "2.5rem",
            }}
            severity="danger"
            tooltip={text.clearCache}
            size={"sm"}
            onClick={onClearCache}
          />
        )}

        {!!stateful && !!resizableColumns && (
          <Button
            type="button"
            icon="pi pi-sync"
            tooltipOptions={{
              position: "left",
            }}
            style={{
              height: "100%",
            }}
            severity="danger"
            tooltip={text.resetColumnsWidths}
            size={"sm"}
            onClick={() => {
              tableRef.current?.resetResizeColumnsWidth();
              tableRef.current?.restoreColumnWidths();
            }}
          />
        )}
      </Flex>
    </Flex>
  );
};

export default TableHeader;
